mapper.select:
SELECT id, user_id, book_id, rule_id, borrow_time, due_time, return_time,
       renew_count, overdue_days, fine_amount, status
FROM borrow_record
WHERE id = #{id}
  AND user_id = #{userId}

mapper.update:
UPDATE borrow_record
SET due_time = #{dueTime},
    renew_count = #{renewCount}
WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'BORROWED'

UPDATE borrow_record
SET return_time = #{returnTime},
    status = #{status},
    overdue_days = #{overdueDays},
    fine_amount = #{fineAmount}
WHERE id = #{id}
  AND user_id = #{userId}
  AND status IN ('BORROWED', 'OVERDUE')

mapper.select:
SELECT br.id, u.username, c.name AS category_name, b.title, b.author, br.borrow_time, br.due_time, br.return_time, br.status, br.renew_count, rule.max_renew_count, br.overdue_days, br.fine_amount, rule.fine_per_day FROM borrow_record br INNER JOIN sys_user u ON br.user_id = u.id INNER JOIN book b ON br.book_id = b.id INNER JOIN book_category c ON b.category_id = c.id INNER JOIN borrow_rule rule ON br.rule_id = rule.id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND b.title LIKE CONCAT('%', #{title}, '%')
AND br.status = #{status}
AND br.borrow_time >= #{startTime}
AND br.borrow_time <= #{endTime}
ORDER BY br.borrow_time DESC, br.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(*) FROM borrow_record br INNER JOIN sys_user u ON br.user_id = u.id INNER JOIN book b ON br.book_id = b.id INNER JOIN book_category c ON b.category_id = c.id INNER JOIN borrow_rule rule ON br.rule_id = rule.id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND b.title LIKE CONCAT('%', #{title}, '%')
AND br.status = #{status}
AND br.borrow_time >= #{startTime}
AND br.borrow_time <= #{endTime}
